from __future__ import annotations

import asyncio
import inspect
import json
import secrets
import threading
import uuid
from collections.abc import Callable, Mapping
from dataclasses import dataclass
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer
from typing import Any, Protocol, TypeGuard, runtime_checkable

from .errors import ConfigurationError, CursorSDKError
from .types import (
    CustomTool,
    LocalAgentOptions,
    _normalize_local_options,
)

TOOL_CALLBACK_SERVICE = "sdk.v1.SdkCustomToolCallbackService"
CONNECT_PROTOCOL_VERSION = "1"

__all__ = [
    "CustomToolsHandler",
    "ToolCallbackEndpoint",
    "ToolCallbackServer",
    "extract_local_custom_tools",
    "prepare_agent_options_custom_tools",
    "unregister_agent_custom_tools",
]


@dataclass(frozen=True)
class ToolCallbackEndpoint:
    url: str
    auth_token: str


@runtime_checkable
class CustomToolsHandler(Protocol):
    def __getitem__(self, tool_name: str) -> CustomTool: ...

    def get(
        self, tool_name: str, default: CustomTool | None = None
    ) -> CustomTool | None: ...

    def keys(self) -> Any: ...


def is_custom_tools_handler(
    handler: object,
) -> TypeGuard[CustomToolsHandler | Mapping[str, CustomTool]]:
    if isinstance(handler, Mapping):
        return all(isinstance(tool, CustomTool) for tool in handler.values())
    return isinstance(handler, CustomToolsHandler)


class ToolCallbackServer:
    """Loopback Connect/JSON server for ``SdkCustomToolCallbackService``.

    Tool execute handlers are registered per ``agent_id`` when agents are
    created or resumed; the bridge forwards MCP invocations with that id.
    """

    def __init__(
        self,
        *,
        host: str = "127.0.0.1",
        port: int = 0,
        auth_token: str | None = None,
        loop: asyncio.AbstractEventLoop | None = None,
    ) -> None:
        self._agents: dict[str, Mapping[str, CustomTool]] = {}
        self._lock = threading.Lock()
        self._auth_token = auth_token or _new_auth_token()
        self._loop = loop
        self._httpd = ThreadingHTTPServer(
            (host, port),
            _make_request_handler(self, self._auth_token),
        )
        self._httpd.daemon_threads = True
        self._serve_thread = threading.Thread(
            target=self._httpd.serve_forever, daemon=True
        )
        self._serve_thread.start()

    def register_agent(
        self,
        agent_id: str,
        tools: CustomToolsHandler | Mapping[str, CustomTool],
    ) -> None:
        if not agent_id:
            raise ConfigurationError("agent_id is required to register custom tools")
        if not is_custom_tools_handler(tools):
            raise ConfigurationError(
                "custom tools must be a mapping of tool names to CustomTool instances."
            )
        normalized = (
            dict(tools)
            if isinstance(tools, Mapping)
            else {name: tools[name] for name in tools.keys()}
        )
        with self._lock:
            self._agents[agent_id] = normalized

    def unregister_agent(self, agent_id: str) -> None:
        with self._lock:
            self._agents.pop(agent_id, None)

    def _get_tools(self, agent_id: str) -> Mapping[str, CustomTool] | None:
        with self._lock:
            return self._agents.get(agent_id)

    @property
    def endpoint(self) -> ToolCallbackEndpoint:
        host, port = self._httpd.server_address
        if isinstance(host, bytes):
            host = host.decode("utf-8")
        if ":" in host and not host.startswith("["):
            host = f"[{host}]"
        return ToolCallbackEndpoint(
            url=f"http://{host}:{port}/",
            auth_token=self._auth_token,
        )

    def close(self) -> None:
        shutdown_thread = threading.Thread(target=self._httpd.shutdown, daemon=True)
        shutdown_thread.start()
        shutdown_thread.join(timeout=5)
        self._serve_thread.join(timeout=5)
        self._httpd.server_close()

    def __enter__(self) -> "ToolCallbackServer":
        return self

    def __exit__(self, exc_type: object, exc: object, tb: object) -> None:
        self.close()


def _new_auth_token() -> str:
    return secrets.token_urlsafe(32)


def _make_request_handler(
    server: ToolCallbackServer,
    auth_token: str,
) -> type[BaseHTTPRequestHandler]:
    from ._store_callback import _BodyFramingError

    class Handler(BaseHTTPRequestHandler):
        def log_message(self, format: str, *args: Any) -> None:
            return

        def do_POST(self) -> None:
            if not self.path.startswith("/"):
                self._write_error(404, "not_found", "Unknown path")
                return
            path = self.path.lstrip("/")
            if path.count("/") != 1:
                self._write_error(404, "not_found", "Unknown path")
                return
            service, method = path.split("/", 1)
            if service != TOOL_CALLBACK_SERVICE:
                self._write_error(404, "not_found", "Unknown service")
                return
            if not self._authorized():
                self._write_error(401, "unauthenticated", "Unauthorized")
                return
            if self.headers.get("Connect-Protocol-Version") != CONNECT_PROTOCOL_VERSION:
                self._write_error(
                    400, "invalid_argument", "Unsupported Connect version"
                )
                return
            try:
                raw = self._read_body()
            except _BodyFramingError:
                self._write_error(
                    400, "invalid_argument", "Invalid request body framing"
                )
                return
            try:
                request = json.loads((raw or b"{}").decode("utf-8"))
            except json.JSONDecodeError:
                self._write_error(400, "invalid_argument", "Invalid JSON body")
                return
            if not isinstance(request, Mapping):
                self._write_error(400, "invalid_argument", "Expected JSON object")
                return
            try:
                response = _dispatch_tool_call(server, method, request)
            except CursorSDKError as error:
                self._write_error(400, "invalid_argument", str(error))
                return
            except Exception as error:
                self._write_error(500, "internal", str(error))
                return
            body = json.dumps(response).encode("utf-8")
            self.send_response(200)
            self.send_header("Content-Type", "application/json")
            self.send_header("Connect-Protocol-Version", CONNECT_PROTOCOL_VERSION)
            self.send_header("Content-Length", str(len(body)))
            self.end_headers()
            self.wfile.write(body)

        def _read_body(self) -> bytes:
            encoding = self.headers.get("Transfer-Encoding", "")
            if "chunked" in encoding.lower():
                return self._read_chunked_body()
            try:
                length = int(self.headers.get("Content-Length", "0"))
            except ValueError as error:
                raise _BodyFramingError from error
            if length < 0:
                raise _BodyFramingError
            return self._read_exact(length) if length > 0 else b""

        def _read_exact(self, size: int) -> bytes:
            buf = bytearray()
            while len(buf) < size:
                chunk = self.rfile.read(size - len(buf))
                if not chunk:
                    raise _BodyFramingError
                buf += chunk
            return bytes(buf)

        def _read_chunked_body(self) -> bytes:
            body = bytearray()
            while True:
                size_token = self.rfile.readline().split(b";", 1)[0].strip()
                try:
                    size = int(size_token, 16)
                except ValueError as error:
                    raise _BodyFramingError from error
                if size == 0:
                    while self.rfile.readline().strip():
                        pass
                    return bytes(body)
                body += self._read_exact(size)
                self._read_exact(2)

        def _authorized(self) -> bool:
            authorization = self.headers.get("Authorization", "")
            if not authorization.startswith("Bearer "):
                return False
            bearer = authorization[len("Bearer ") :]
            return secrets.compare_digest(bearer, auth_token)

        def _write_error(self, status: int, code: str, message: str) -> None:
            payload = {"code": code, "message": message}
            body = json.dumps(payload).encode("utf-8")
            self.send_response(status)
            self.send_header("Content-Type", "application/json")
            self.send_header("Connect-Protocol-Version", CONNECT_PROTOCOL_VERSION)
            self.send_header("Content-Length", str(len(body)))
            self.end_headers()
            self.wfile.write(body)

    return Handler


def _dispatch_tool_call(
    server: ToolCallbackServer,
    method: str,
    request: Mapping[str, Any],
) -> dict[str, Any]:
    if method != "CallCustomTool":
        raise CursorSDKError(f"Unknown method: {method}")
    agent_id = _require_string(request, "agentId", "agent_id")
    tool_name = _require_string(request, "toolName", "tool_name")
    args_value = request.get("args") or {}
    if not isinstance(args_value, Mapping):
        raise CursorSDKError("args must be a JSON object")
    tool_call_id = request.get("toolCallId") or request.get("tool_call_id")
    if tool_call_id is not None and not isinstance(tool_call_id, str):
        raise CursorSDKError("toolCallId must be a string")

    tools = server._get_tools(agent_id)
    if tools is None:
        raise CursorSDKError(f"No custom tools registered for agent {agent_id}")
    tool = tools.get(tool_name)
    if tool is None:
        raise CursorSDKError(f"Unknown custom tool {tool_name!r} for agent {agent_id}")

    from .types import CustomToolContext

    try:
        result = tool.execute(
            dict(args_value),
            CustomToolContext(tool_call_id=tool_call_id),
        )
    except Exception as error:
        return {
            "result": {
                "content": [{"type": "text", "text": str(error)}],
                "isError": True,
            }
        }
    if inspect.isawaitable(result):
        result = _resolve_awaitable(result, server._loop)
    return {"result": _normalize_custom_tool_result(result)}


def _normalize_custom_tool_result(result: Any) -> Any:
    """Shape host results for ``CallCustomToolResponse.result`` (protobuf Struct).

    The bridge decodes this field with Connect + ``Struct``; a bare string is
    invalid on the wire and surfaces as a generic tool failure in the agent.
    """
    if isinstance(result, str):
        return {"content": [{"type": "text", "text": result}]}
    if isinstance(result, Mapping):
        if "content" in result and isinstance(result.get("content"), list):
            return dict(result)
        return result
    return {"content": [{"type": "text", "text": str(result)}]}


def _resolve_awaitable(awaitable: Any, loop: asyncio.AbstractEventLoop | None) -> Any:
    if loop is None:
        if inspect.iscoroutine(awaitable):
            awaitable.close()
        raise CursorSDKError(
            "async custom tool execute methods require an AsyncClient / AsyncBridge; "
            "no event loop is available to run the coroutine."
        )

    async def _runner() -> Any:
        return await awaitable

    return asyncio.run_coroutine_threadsafe(_runner(), loop).result()


def _require_string(request: Mapping[str, Any], camel: str, snake: str) -> str:
    value = request.get(camel) or request.get(snake)
    if not isinstance(value, str) or not value:
        raise CursorSDKError(f"{camel} is required")
    return value


def tool_callback_bridge_argv(endpoint: ToolCallbackEndpoint) -> list[str]:
    return [
        "--tool-callback-url",
        endpoint.url,
        "--tool-callback-auth-token",
        endpoint.auth_token,
    ]


def _custom_tools_on_wire(local: Mapping[str, Any] | None) -> Mapping[str, Any] | None:
    if not isinstance(local, Mapping):
        return None
    custom_tools = local.get("customTools") or local.get("custom_tools")
    return custom_tools if isinstance(custom_tools, Mapping) else None


def needs_tool_callback_server_in_options(options: Mapping[str, Any]) -> bool:
    local = options.get("local")
    return needs_tool_callback_server(local if isinstance(local, Mapping) else None)


def needs_tool_callback_server(local: Mapping[str, Any] | None) -> bool:
    custom_tools = _custom_tools_on_wire(local)
    return custom_tools is not None and len(custom_tools) > 0


def local_options_wire(
    local: LocalAgentOptions | Mapping[str, Any] | None,
) -> Mapping[str, Any] | None:
    if local is None:
        return None
    if isinstance(local, LocalAgentOptions):
        return local.to_json()
    return _normalize_local_options(dict(local))


def _custom_tools_from_local_value(
    local: LocalAgentOptions | Mapping[str, Any],
    *,
    skip_names: set[str] | None = None,
) -> dict[str, CustomTool] | None:
    if isinstance(local, LocalAgentOptions):
        raw = local.custom_tools
    elif isinstance(local, Mapping):
        raw = local.get("custom_tools") or local.get("customTools")
    else:
        return None
    if not raw:
        return None
    skip = skip_names or set()
    tools: dict[str, CustomTool] = {}
    for name, value in raw.items():
        # A key supplied by a higher-precedence source (the ``local=`` override)
        # wins, so don't parse or validate this entry: a metadata-only base
        # entry (no ``execute``) is legitimately replaced by the override.
        if str(name) in skip:
            continue
        if isinstance(value, CustomTool):
            tools[str(name)] = value
        elif isinstance(value, Mapping) and callable(value.get("execute")):
            tools[str(name)] = CustomTool(
                execute=value["execute"],  # type: ignore[arg-type]
                description=value.get("description"),
                input_schema=value.get("input_schema") or value.get("inputSchema"),
            )
        else:
            raise ConfigurationError(
                f'local.custom_tools["{name}"] must be a CustomTool instance'
            )
    return tools


def extract_custom_tools_before_wire(
    options: LocalAgentOptions | Mapping[str, Any] | Any | None = None,
    *,
    local: LocalAgentOptions | Mapping[str, Any] | None = None,
) -> dict[str, CustomTool] | None:
    """Read ``CustomTool`` execute handlers before options are serialized for RPC.

    Mirrors ``options_to_json``'s deep merge: both ``options.local`` and the
    ``local=`` override contribute, with ``local=`` winning on key conflicts.
    This keeps the registered handlers in sync with the ``customTools`` metadata
    placed on the wire, so no advertised tool is left without a handler.

    The override is resolved first so that a key it supplies is skipped when
    parsing ``options.local``; this lets the override rescue a metadata-only base
    entry (e.g. one missing ``execute``) instead of raising on it.
    """
    merged: dict[str, CustomTool] = {}
    if local is not None:
        override = _custom_tools_from_local_value(local)
        if override:
            merged.update(override)
    if options is not None:
        if isinstance(options, LocalAgentOptions):
            base_value: LocalAgentOptions | Mapping[str, Any] | None = options
        elif hasattr(options, "local") and getattr(options, "local", None) is not None:
            base_value = options.local
        elif isinstance(options, Mapping) and options.get("local") is not None:
            base_value = options["local"]
        else:
            base_value = None
        if base_value is not None:
            base = _custom_tools_from_local_value(base_value, skip_names=set(merged))
            if base:
                for name, tool in base.items():
                    merged.setdefault(name, tool)
    return merged or None


def extract_local_custom_tools(
    options: Mapping[str, Any],
) -> dict[str, CustomTool] | None:
    """Return execute handlers from wire ``options`` when still present (tests)."""
    local = options.get("local")
    if not isinstance(local, Mapping):
        return None
    return _custom_tools_from_local_value(local)


def prepare_agent_options_custom_tools(
    *,
    bridge_tool_callback_enabled: bool,
    bridge_is_sdk_owned: bool,
    options: Mapping[str, Any],
    tools: Mapping[str, CustomTool],
    agent_id: str | None = None,
    register: Callable[[str, Mapping[str, CustomTool]], None] | None = None,
) -> Mapping[str, Any]:
    """Assign ``agentId`` for new agents and register host execute handlers."""
    assert_local_custom_tools_not_on_cloud(options)
    if not tools:
        return options
    if not bridge_tool_callback_enabled:
        if bridge_is_sdk_owned:
            raise ConfigurationError(
                "local.custom_tools requires a bridge launched via "
                "Client.launch_bridge (tool callback server missing)."
            )
        return options
    if register is None:
        raise ConfigurationError(
            "local.custom_tools requires an active tool callback server on the bridge."
        )
    # An explicit ``agent_id`` (resume target) must win: ResumeAgent binds
    # host-backed tools by the top-level RPC ``agent_id``, so registering under a
    # stray ``options.agentId`` would key callbacks to the wrong agent. For
    # create, ``agent_id`` is None and we fall back to any caller-supplied id.
    resolved_agent_id = (
        agent_id
        or str(options.get("agentId") or options.get("agent_id") or "")
        or str(uuid.uuid4())
    )
    register(resolved_agent_id, tools)
    merged = dict(options)
    merged["agentId"] = resolved_agent_id
    merged.pop("agent_id", None)
    return merged


def unregister_agent_custom_tools(
    bridge: Any,
    agent_id: str,
) -> None:
    server = getattr(bridge, "_tool_callback_server", None)
    if server is not None:
        server.unregister_agent(agent_id)


def assert_local_custom_tools_not_on_cloud(
    options: Mapping[str, Any],
) -> None:
    if not options.get("cloud"):
        return
    if needs_tool_callback_server_in_options(options):
        raise ConfigurationError(
            "local.custom_tools is only supported for local SDK agents. "
            "Omit custom_tools when using cloud=...."
        )


def ensure_custom_tool_callback_for_agent_options(
    *,
    bridge_tool_callback_enabled: bool,
    bridge_is_sdk_owned: bool,
    options: Mapping[str, Any],
) -> None:
    assert_local_custom_tools_not_on_cloud(options)
    if not needs_tool_callback_server_in_options(options):
        return
    if bridge_tool_callback_enabled:
        return
    if not bridge_is_sdk_owned:
        # Connect mode: the sync Client lazily starts a loopback callback server
        # and points the running bridge at it via SetToolCallback (same host).
        # No upfront error here; the client wires the server before the RPC.
        return
    raise ConfigurationError(
        "Agent options use local.custom_tools that call back to the host, but "
        "the bridge was launched without a tool callback server. Use "
        "Client.launch_bridge(...) before create_agent / resume_agent."
    )


def reject_send_local_custom_tools(send_options: Mapping[str, Any] | None) -> None:
    if not isinstance(send_options, Mapping):
        return
    local = send_options.get("local")
    if not isinstance(local, Mapping):
        return
    if needs_tool_callback_server(local):
        raise ConfigurationError(
            "local.custom_tools is only supported on Agent.create / Agent.resume "
            "local options, not on SendOptions."
        )
